import React, { useEffect, useState } from 'react';
import './App.css';
import { Element, scroller } from 'react-scroll';
import About from './components/about';
import Home from './components/home';
import Navbar from './components/navbar';
import Services from './components/services';
import Contact from './components/contact';
import Footers from './components/footer';
import ScrollToTopArrow from './components/scrolltoparrow';


function App() {
  const [visibleSection, setVisibleSection] = useState('');

  const handleSetActive = (to) => {
    setVisibleSection(to);
  };

  const scrollToSection = (section) => {
    scroller.scrollTo(section, {
      duration: 800,
      delay: 0,
      smooth: 'easeInOutQuart',
    });
  };

  useEffect(() => {
    // Event listener for scroll
    const handleScroll = () => {
      // Implement logic to determine which section is currently in view
      // You can use the window.scrollY value and element offsets
      // Set the visible section using setVisibleSection
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);



  return (
    <div>
      <Navbar scrollToSection={scrollToSection} />
      <Element name="home" className={`section ${visibleSection === 'home' ? 'visible' : ''}`}>
        <Home />
      </Element>
      <Element name="about" className={`section ${visibleSection === 'about' ? 'visible' : ''}`}>
        <About />
      </Element>
      <Element name="services" className={`section ${visibleSection === 'services' ? 'visible' : ''}`}>
        <Services />
      </Element>
      <Element name="contact" className={`section ${visibleSection === 'contact' ? 'visible' : ''}`}>
        <Contact />
      </Element>
      <Footers />
      <ScrollToTopArrow />
    </div>
  );
}

export default App;
